const fs = require('fs');
const content = fs.readFileSync('src/sections/index.ts', 'utf8');
// Match all export { ... } blocks
const blocks = content.match(/export \{[\s\S]*?\} from/g);
const allNames = [];
for (const block of blocks) {
  const inner = block.replace('export {', '').replace('} from', '');
  const names = inner.split(',').map(s => s.trim()).filter(Boolean);
  for (const n of names) {
    // Handle 'default as X'
    const name = n.includes(' as ') ? n.split(' as ')[1].trim() : n;
    allNames.push(name);
  }
}
// Remove duplicates
const unique = [...new Set(allNames)];
console.log('Exported names:', unique.sort().join(', '));
console.log('Count:', unique.length);
